export enum ClientStage {
  PROSPECT = 'PROSPECT', // 拓展期
  ACTIVE = 'ACTIVE',     // 投放期
  CHURN = 'CHURN',       // 流失期
}

export interface MetricPoint {
  date: string;
  value: number;
  forecast?: number;
}

export interface FunnelHistoryPoint {
  date: string;
  impressions: number;
  downloads: number;
  activations: number;
}

export interface CompetitorData {
  name: string;
  marketShare: number;
  overlap: number;
}

// 1. 后端转化与LTV
export interface ConversionMetrics {
  retention1d: number; // 次留
  retention7d: number;
  payRate: number; // 付费率 PUR
  ecpm: number;
  ltv: number;
  roasIAP: number; // 内购ROAS
  roasIAA: number; // 变现ROAS
  funnel: { stage: string; value: number; rate: number }[]; // 漏斗
}

// 2. 素材创意
export interface CreativeStats {
  topCreatives: { id: string; type: 'video' | 'image'; url: string; ctr: number; name: string }[];
  lifecycleDays: number; // 衰退周期
  tags: string[]; // 偏好标签
  rejectionRate: number; // 拒审率
}

// 3. 竞价诊断
export interface BiddingData {
  winRate: number;
  sov: number; // Share of Voice
  lossReasons: { reason: string; percentage: number }[];
}

// 4. 人群画像
export interface AudienceData {
  demographics: { label: string; value: number }[]; // e.g., Gender, Age
  penetrationRate: number; // 核心人群渗透率
  competitorOverlap: number; // 重合度
}

// 5. 财务健康
export interface FinancialHealth {
  paymentMode: 'Prepay' | 'Postpay';
  accountPeriodDays: number; // 账期
  walletRunwayDays: number; // 余额预计支撑天数
  overdueHistory: number; // 逾期次数
  refundRate: number; // 退款率
}

// 6. 应用健康度
export interface AppHealth {
  storeRating: number;
  crashRate: number;
  packageSizeMB: number;
  negativeSentimentKeywords: string[];
}

// 7. 风控合规
export interface RiskProfile {
  violationCount: number;
  fraudScore: number; // 0-100 (High is bad)
  relatedBannedAccounts: number;
}

// 8. 增长机会
export interface GrowthOpportunity {
  recommendedKeywords: { keyword: string; searchVolume: string; competition: 'Low' | 'Med' | 'High' }[];
  missedPlacements: { name: string; potentialLift: string }[];
  industryTrends: string[];
}

export interface ChannelData {
  name: string;
  value: number;
}

export interface ClientProfile {
  id: string;
  name: string;
  logo: string;
  industry: string;
  stage: ClientStage;
  apps: string[];
  competitorPlatforms: string[];

  // Budget Info
  annualBudget?: number;
  budgetSpent?: number;

  // Prospecting
  bdOwner?: string;
  prospectStage?: 'Lead' | 'Contacted' | 'Meeting' | 'Negotiation' | 'Onboarding';
  lastContactDate?: string;

  // Active (Basic)
  totalSpend?: number;
  roi?: number;
  impressions?: number;
  conversions?: number;
  spendTrend?: MetricPoint[];
  funnelHistory?: FunnelHistoryPoint[]; // New: For trend analysis
  competitorAnalysis?: CompetitorData[];
  channelDistribution?: ChannelData[];

  // Active (Advanced 8 Dimensions)
  conversionMetrics?: ConversionMetrics;
  creativeStats?: CreativeStats;
  biddingData?: BiddingData;
  audienceData?: AudienceData;
  financialHealth?: FinancialHealth;
  appHealth?: AppHealth;
  riskProfile?: RiskProfile;
  growthOpp?: GrowthOpportunity;

  // Churn
  churnReason?: string;
  riskScore?: number;
  lastActiveDate?: string;
  retentionPlan?: string[];
}

export interface InsightResponse {
  summary: string;
  actionItems: string[];
  prediction?: string;
}

// --- NEW DASHBOARD TYPES ---

export interface DashboardMetric {
  label: string;
  value: string | number;
  unit?: string;
  changeRate: number; // percentage
  trend: 'up' | 'down' | 'flat';
  comparison: 'DoD' | 'WoW' | 'MoM';
}

export interface IndustryHeatmapItem {
  industry: string;
  bidIntensity: number; // 0-100, determines color
  trafficVolume: 'High' | 'Med' | 'Low'; // determines size or label
  trend: 'up' | 'down';
}

export interface RiskAlertItem {
  id: string;
  clientName: string;
  type: 'Anomaly' | 'Compliance' | 'Budget';
  message: string;
  severity: 'High' | 'Medium' | 'Low';
  timestamp: string;
}

export interface PlatformOverview {
  cockpit: {
    realTimeSpend: DashboardMetric;
    ecpm: DashboardMetric;
    ctr: DashboardMetric;
    cvr: DashboardMetric;
    fillRate: DashboardMetric;
    healthScore: number; // 0-100
  };
  segmentation: {
    lifecycle: { name: string; value: number; color: string }[];
    tiers: { name: string; value: number }[]; // S, A, B
    industryHeatmap: IndustryHeatmapItem[];
  };
  risks: {
    alerts: RiskAlertItem[];
    budgetCapHitRate: number; // percentage of clients near cap
    complianceRiskCount: number;
  };
  marketTrends: {
    trafficForecast: MetricPoint[];
    bidTrends: { category: string; data: MetricPoint[] }[];
  };
}

export interface PlatformStats {
  revenue: {
    total: number;
    goal: number;
    trend: MetricPoint[];
  };
  clients: {
    activeCount: number;
    goal: number;
    trend: MetricPoint[];
  };
}

